import { NextResponse } from "next/server";
import { writeFile, readFile } from "fs/promises";
import path from "path";
import { createWorker } from "tesseract.js";
import * as pdfjsLib from "pdfjs-dist";
import { createCanvas } from "canvas"; // ✅ Added this import
import sharp from "sharp";

// Set worker path for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = path.resolve(
  process.cwd(),
  "node_modules/pdfjs-dist/build/pdf.worker.js"
);

const uploadDir = path.join(process.cwd(), "public/uploads");

async function savePDF(file: File): Promise<string> {
  const filePath = path.join(uploadDir, file.name);
  const buffer = Buffer.from(await file.arrayBuffer());
  await writeFile(filePath, buffer);
  return filePath;
}

async function convertPDFToImages(pdfPath: string): Promise<string[]> {
  const data = await readFile(pdfPath);
  const pdfDoc = await pdfjsLib.getDocument({ data }).promise;
  const numPages = pdfDoc.numPages;
  const imagePaths: string[] = [];

  console.log(`PDF Loaded Successfully: ${numPages} pages found`);

  for (let i = 1; i <= numPages; i++) {
    const page = await pdfDoc.getPage(i);
    const viewport = page.getViewport({ scale: 2.0 });

    // ✅ Fix: Now createCanvas is defined
    const canvas = createCanvas(viewport.width, viewport.height);
    const context = canvas.getContext("2d");

    const renderContext = {
      canvasContext: context,
      viewport: viewport,
    };

    await page.render(renderContext).promise;

    const imagePath = path.join(uploadDir, `page-${i}.png`);
    await sharp(canvas.toBuffer()).png().toFile(imagePath);
    imagePaths.push(imagePath);

    console.log(`Saved page ${i} image at: ${imagePath}`);
  }

  return imagePaths;
}

async function extractTextFromImages(imagePaths: string[]): Promise<string> {
  const worker = await createWorker("eng");
  let fullText = "";

  for (const imagePath of imagePaths) {
    const { data } = await worker.recognize(imagePath);
    fullText += data.text + "\n";
    console.log(`Extracted text from image: ${imagePath}`);
  }

  await worker.terminate();
  return fullText;
}

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    const pdfPath = await savePDF(file);
    const imagePaths = await convertPDFToImages(pdfPath);
    const extractedText = await extractTextFromImages(imagePaths);

    return NextResponse.json({ text: extractedText });
  } catch (error) {
    console.error("OCR Extraction Error:", error);
    return NextResponse.json(
      { error: "OCR Extraction Failed" },
      { status: 500 }
    );
  }
}
